/////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
// SATA RX -> UART TX  (include internal buffer)
/////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
uart_tx #(
    .CLK_DIV                  ( 1302                                  ),   // 150MHz/115200Hz=1302
    .PARITY                   ( "NONE"                                ),   // "NONE", "ODD" or "EVEN"
    .ASIZE                    ( 15                                    ),   // Specify UART TX buffer depth = 2^15 = 32768
    .DWIDTH                   ( 4                                     ),   // Specify width of tx_data , that is, how many bytes can it input per clock cycle
    .ENDIAN                   ( "LITTLE"                              ),   // "LITTLE" or "BIG"
    .MODE                     ( "HEX"                                 ),   // "RAW", "PRINTABLE", "HEX" or "HEXSPACE"
    .END_OF_DATA              ( ""                                    ),   // Dont send extra byte after each tx_data
    .END_OF_PACK              ( "\n"                                  )    // send extra byte "\n" after each tx_last=1

always @ (posedge DRPCLK_IN or posedge CPLLRESET_IN)
    if (CPLLRESET_IN) begin
        {gtrxreset2, gtrxreset1} <= 2'b0;
        rxpmaresetdone3 <= 1'b0;
    end else begin
        {gtrxreset2, gtrxreset1} <= {gtrxreset1, ~RX_PCS_RESETN};
        rxpmaresetdone3 <= rxpmaresetdone2;
    end

always @ (posedge DRPCLK_IN or posedge CPLLRESET_IN)
    if (CPLLRESET_IN) begin
        gtrxreset_o <= 1'b0;
        drp_rddata <= 16'b0;
        state <= IDLE;
    end else begin
        gtrxreset_o <= 1'b0;
        case (state)
            IDLE : begin
                if (gtrxreset2)
                    state <= DRP_RD;
                else
                    state <= IDLE;
            end
            DRP_RD : begin
                gtrxreset_o <= 1'b1;
                state <= WAIT_RD_DATA;
            end
            WAIT_RD_DATA : begin
                gtrxreset_o <= 1'b1;
                if (drprdy_i) begin
                    drp_rddata <= drpdo_i;
                    state <= WR_16;
                end else begin
                    state <= WAIT_RD_DATA;
                end
            end
            WR_16 : begin
                gtrxreset_o <= 1'b1;
                state <= WAIT_WR_DONE1;
            end
            WAIT_WR_DONE1 : begin
                gtrxreset_o <= 1'b1;
                if (drprdy_i)
                    state <= WAIT_PMA_RESET;
                else
                    state <= WAIT_WR_DONE1;
            end
            WAIT_PMA_RESET : begin
                gtrxreset_o <= gtrxreset2;
                if (!rxpmaresetdone2 & rxpmaresetdone3)
                    state <= WR_20;
                else
                    state <= WAIT_PMA_RESET;
            end
            WR_20 : begin
                state <= WAIT_WR_DONE2;
            end
            WAIT_WR_DONE2 : begin
                if (drprdy_i)
                    state <= IDLE;
                else
                    state <= WAIT_WR_DONE2;
            end
        endcase
    end

always @ (*) begin       // drives DRP interface
    drpen_i = 1'b0;
    drpwe_i = 1'b0;
    drpdi_i = 16'b0;
    if(~drp_op_done) begin
        case (state)
            DRP_RD : begin
                drpen_i = 1'b1;
            end
            WR_16 : begin
                drpen_i = 1'b1;
                drpwe_i = 1'b1;
                drpdi_i = {drp_rddata[15:12], 1'b0, drp_rddata[10:0]};
            end
            WR_20 : begin
                drpen_i = 1'b1;
                drpwe_i = 1'b1;
                drpdi_i = drp_rddata;
            end
        endcase
    end
end

